{
  "handoff_brief": {
    "recipient": "Shaq",
    "task_context": "Implement per-API-key rate limiting middleware. Four agents have provided domain rules, architecture, operational requirements, and a code review. Kobe's review refined MJ's original design — use a true sliding window (Redis sorted sets), not a fixed-window counter, to match Bird's 'rolling window' domain rule and avoid boundary burst issues.",
    "domain_rules": [
      {
        "rule": "API rate limit is 100 requests per 60-second rolling window per API key",
        "testable_assertion": "Given an API key that has made 100 requests within any 60-second sliding window, the 101st request within that window returns HTTP 429"
      },
      {
        "rule": "Exceeding the limit returns HTTP 429 with a Retry-After header indicating seconds until capacity is available",
        "testable_assertion": "The 429 response includes a Retry-After header whose value is the number of seconds until the oldest request in the current window expires (not a fixed value)"
      },
      {
        "rule": "Rate limiter must fail open if Redis is unavailable",
        "testable_assertion": "When Redis is unreachable, all requests are allowed through and the redis_unavailable_total metric increments"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Use Redis sorted sets for a true sliding window (not fixed-window counters)",
        "implementation_note": "MJ originally proposed fixed-window counters with key pattern rate_limit:{api_key}:{window_start_unix}. Kobe identified this allows 2x burst at window boundaries. Use sorted sets instead: key = rate_limit:{api_key}, members = request timestamps (score = unix timestamp). On each request: ZREMRANGEBYSCORE to remove entries older than now-60s, ZCARD to count, ZADD if under limit. Set key TTL to 60s as a safety net."
      },
      {
        "decision": "Middleware runs before all authenticated routes",
        "implementation_note": "Rate limiting is applied after authentication (so the API key is available) but before any business logic. This is a middleware/filter, not per-endpoint."
      },
      {
        "decision": "Retry-After header must be computed dynamically from the sorted set",
        "implementation_note": "Retry-After = ceiling of (oldest_member_score + 60 - now). This is the number of seconds until the oldest request in the window expires, freeing one slot. Do NOT return a fixed value like 60."
      },
      {
        "decision": "Fail-open on Redis failure with observability",
        "implementation_note": "Wrap all Redis calls in try/catch. On any Redis error, allow the request through and increment redis_unavailable_total counter. Log at WARN level. This must be explicitly tested — do not rely on implicit behavior."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "101st request in a 60-second window is rejected",
        "given": "An API key has made 100 requests within the last 60 seconds",
        "when": "A 101st request arrives",
        "then": "HTTP 429 is returned with a Retry-After header showing seconds until capacity frees up"
      },
      {
        "criterion": "Window rolls correctly (no boundary burst)",
        "given": "An API key made 100 requests between t=0s and t=30s",
        "when": "At t=61s a new request arrives",
        "then": "The request succeeds because the earliest requests have fallen outside the 60s sliding window"
      },
      {
        "criterion": "No 2x burst at window boundaries",
        "given": "An API key made 99 requests at t=59s and 1 request at t=60s",
        "when": "A request arrives at t=60.5s",
        "then": "It is rejected (the 99 requests from t=59s are still within the 60s sliding window)"
      },
      {
        "criterion": "Fail-open when Redis is down",
        "given": "Redis is unavailable",
        "when": "Any request arrives",
        "then": "The request is allowed through, redis_unavailable_total metric increments, and a WARN log is emitted"
      },
      {
        "criterion": "Observability metrics are emitted",
        "given": "Rate limiting is active",
        "when": "A request is rate-limited OR Redis is unavailable",
        "then": "rate_limit_exceeded_total or redis_unavailable_total counter increments respectively"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "rolling window",
        "technical_term": "sliding window via Redis sorted set",
        "definition": "A continuously moving 60-second time window where the oldest request ages out in real time, as opposed to a fixed-window counter that resets at discrete intervals"
      },
      {
        "domain_term": "Retry-After",
        "technical_term": "TTL of oldest sorted set member relative to window boundary",
        "definition": "The number of whole seconds until the oldest request in the current window expires, computed as ceil(oldest_score + 60 - now)"
      }
    ],
    "contradictions_resolved": [
      {
        "conflict": "MJ proposed a fixed-window counter (rate_limit:{api_key}:{window_start_unix} with TTL), but Bird's domain rule specifies a 'rolling window' and Kobe flagged that fixed windows allow 2x burst at boundaries",
        "resolution": "Adopt Kobe's recommendation: use Redis sorted sets for a true sliding window. This satisfies Bird's rolling window requirement and eliminates the boundary burst problem. MJ's key pattern is replaced with a single key per API key containing timestamped members."
      },
      {
        "conflict": "MJ described Retry-After as derived from 'TTL of the current window key' (fixed-window concept), while Pippen specified it must not be a fixed value",
        "resolution": "With sorted sets, Retry-After is computed as the time until the oldest member in the set falls outside the 60s window, giving a precise dynamic value per Pippen's requirement"
      }
    ],
    "open_questions": []
  },
  "escalations": [],
  "confidence": {
    "level": 92,
    "high_confidence_areas": [
      "Domain rules are clear and unambiguous from Bird",
      "Kobe's sorted-set refinement cleanly resolves MJ's boundary-burst issue",
      "Pippen's operational requirements (fail-open, metrics, dynamic Retry-After) are concrete and testable",
      "All four agents are aligned on the final direction after Kobe's review"
    ],
    "low_confidence_areas": [
      "Exact Redis sorted set commands and atomicity (MULTI/EXEC vs Lua script) not specified — Shaq should use a Lua script for atomic ZREMRANGEBYSCORE + ZCARD + ZADD to avoid race conditions"
    ],
    "assumptions": [
      "Rate limiting is per API key only, not per endpoint or per user",
      "The 100-request limit and 60-second window are not configurable at runtime (hardcoded or config-file driven)",
      "Redis is already available in the infrastructure — no new provisioning needed"
    ]
  }
}

